class Solution:
    def findSpecialInteger(self, arr) -> int:
        n = len(arr)
        quarter = n // 4
        for i in range(0, n, quarter + 1 if quarter else 1):
            candidate = arr[i]
            if arr.count(candidate) * 4 > n:
                return candidate
        # fallback: check every quarter boundary
        for pos in [n // 4, n // 2, 3 * n // 4]:
            candidate = arr[pos]
            if arr.count(candidate) * 4 > n:
                return candidate
        return arr[0]

