var findSpecialInteger = function(arr) {
    const n = arr.length;
    const positions = [Math.floor(n / 4), Math.floor(n / 2), Math.floor(3 * n / 4)];
    for (const pos of positions) {
        const candidate = arr[pos];
        let lo = 0, hi = n;
        while (lo < hi) { const m = (lo + hi) >> 1; if (arr[m] < candidate) lo = m + 1; else hi = m; }
        let lo2 = 0, hi2 = n;
        while (lo2 < hi2) { const m = (lo2 + hi2) >> 1; if (arr[m] <= candidate) lo2 = m + 1; else hi2 = m; }
        if ((lo2 - lo) * 4 > n) return candidate;
    }
    return arr[0];
};
